// Termine verarbeiten und mit "Gesendet"-Liste abgleichen
const termine = $('Termine aus Google Sheets').all();
const gesendetItems = $('Bereits gesendet laden').all();

// Set von bereits gesendeten Erinnerungen
const gesendet = new Set();
for (const item of gesendetItems) {
  const key = `${item.json.Telefon}_${item.json.Datum}_${item.json.Uhrzeit}_${item.json.Typ}`;
  gesendet.add(key);
}

const now = new Date();
const results = [];

for (const item of termine) {
  const data = item.json;

  // Pflichtfelder pruefen
  const datum = data.Datum || data.datum;
  const zeit = data.Uhrzeit || data.uhrzeit || data.Zeit || '09:00';
  const name = data.Schueler || data.Name || data.schueler || data.name || '';
  let telefon = data.Telefon || data.telefon || data.Handy || data.handy || data.WhatsApp || '';
  const fahrlehrer = data.Fahrlehrer || data.fahrlehrer || data.Lehrer || '';
  const art = data.Art || data.art || data.Typ || 'Fahrstunde';
  const status = (data.Status || data.status || '').toLowerCase();

  // Abgesagte Termine ueberspringen
  if (status === 'abgesagt' || status === 'cancelled' || status === 'storniert') continue;
  if (!datum || !telefon || !name) continue;

  // Telefonnummer bereinigen
  telefon = telefon.toString().replace(/[\s\-\/\(\)]/g, '');
  if (!telefon.startsWith('+')) {
    telefon = '+49' + telefon.replace(/^0/, '');
  }

  // Termin-Zeitpunkt berechnen
  let terminDatum;
  try {
    // Verschiedene Datumsformate unterstuetzen
    if (datum.includes('.')) {
      // DD.MM.YYYY Format
      const parts = datum.split('.');
      terminDatum = new Date(`${parts[2]}-${parts[1].padStart(2,'0')}-${parts[0].padStart(2,'0')}T${zeit}:00`);
    } else {
      // YYYY-MM-DD Format
      terminDatum = new Date(`${datum}T${zeit}:00`);
    }
  } catch(e) {
    continue;
  }

  if (isNaN(terminDatum.getTime())) continue;

  // Stunden bis zum Termin
  const stundenBis = (terminDatum.getTime() - now.getTime()) / (1000 * 60 * 60);

  // 24h Erinnerung (23-25h vorher)
  if (stundenBis >= 23 && stundenBis <= 25) {
    const key = `${telefon}_${datum}_${zeit}_24h`;
    if (!gesendet.has(key)) {
      const optionen = { weekday: 'long', day: 'numeric', month: 'long' };
      results.push({
        json: {
          schuelerName: name,
          schuelerTelefon: telefon,
          fahrlehrerName: fahrlehrer,
          terminArt: art,
          terminDatum: datum,
          terminZeit: zeit,
          terminDatumFormatiert: terminDatum.toLocaleDateString('de-DE', optionen),
          terminZeitFormatiert: zeit,
          erinnerungsTyp: '24h',
          stundenBisTermin: Math.round(stundenBis * 10) / 10
        }
      });
    }
  }

  // 2h Erinnerung (1.5-2.5h vorher)
  if (stundenBis >= 1.5 && stundenBis <= 2.5) {
    const key = `${telefon}_${datum}_${zeit}_2h`;
    if (!gesendet.has(key)) {
      results.push({
        json: {
          schuelerName: name,
          schuelerTelefon: telefon,
          fahrlehrerName: fahrlehrer,
          terminArt: art,
          terminDatum: datum,
          terminZeit: zeit,
          terminDatumFormatiert: terminDatum.toLocaleDateString('de-DE', { weekday: 'long', day: 'numeric', month: 'long' }),
          terminZeitFormatiert: zeit,
          erinnerungsTyp: '2h',
          stundenBisTermin: Math.round(stundenBis * 10) / 10
        }
      });
    }
  }
}

return results.length > 0 ? results : [{ json: { skip: true } }];

// Eingehende Nachricht verarbeiten
const body = $input.first().json.body || $input.first().json;
const messageBody = (body.Body || body.body || '').trim().toUpperCase();
const from = body.From || body.from || '';

// Nummer extrahieren
const telefon = from.replace('whatsapp:', '').trim();

if (messageBody === 'ABSAGE' || messageBody === 'CANCEL' || messageBody === 'STORNIEREN') {
  return [{
    json: {
      action: 'absage',
      telefon,
      message: messageBody,
      timestamp: new Date().toISOString()
    }
  }];
}

if (messageBody === 'OK' || messageBody === 'JA' || messageBody === 'BESTÄTIGT') {
  return [{
    json: {
      action: 'bestaetigung',
      telefon,
      message: messageBody,
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    action: 'unbekannt',
    telefon,
    message: messageBody,
    timestamp: new Date().toISOString()
  }
}];

